import React from "react";
import { Archive } from "lucide-react";
import { ToolbarProps } from "../types";

/**
 * Componente Toolbar da aplicação
 * Exibe ações disponíveis para os itens selecionados
 * 
 * @param selectedIds - Array com IDs dos itens selecionados
 * @param onArchive - Função callback para arquivar itens selecionados
 */
const Toolbar = ({ selectedIds, onArchive }: ToolbarProps) => {
  // Verifica se há itens selecionados para habilitar/desabilitar botões
  const hasSelection = selectedIds.length > 0;
  
  return (
    <div className="flex gap-2 p-4 border-b bg-white">
      {/* Botão de arquivar */}
      <button
        disabled={!hasSelection}
        onClick={onArchive}
        className={`flex items-center gap-2 px-4 py-2 text-sm font-medium rounded-md transition-colors duration-200 ${
          hasSelection
            ? "bg-blue-600 text-white hover:bg-blue-700"
            : "bg-gray-100 text-gray-400 cursor-not-allowed"
        }`}
        title={hasSelection ? `Arquivar ${selectedIds.length} item(ns)` : "Selecione itens para arquivar"}
      >
        <Archive size={16} />
        <span>Arquivar</span>
        {hasSelection && (
          <span className="bg-blue-800 text-white text-xs px-2 py-1 rounded-full">
            {selectedIds.length}
          </span>
        )}
      </button>
      
      {/* Informação sobre seleção */}
      {hasSelection && (
        <div className="flex items-center text-sm text-gray-600 ml-4">
          <span>{selectedIds.length} item(ns) selecionado(s)</span>
        </div>
      )}
    </div>
  );
};

export default Toolbar;
